using System.Collections.Frozen;

namespace CatalogSvc;

public record ProductInfo(string Category, decimal Price);

public class ProductCatalog
{
    private readonly Dictionary<string, ProductInfo> _products = new(StringComparer.OrdinalIgnoreCase);

    // Reverse index: category → product codes (O(1) lookup by category)
    private readonly Dictionary<string, List<string>> _categoryIndex =
        new(StringComparer.OrdinalIgnoreCase);

    private FrozenDictionary<string, ProductInfo>? _frozen;

    public void AddProduct(string code, string category, decimal price)
    {
        if (_products.TryGetValue(code, out var existing))
        {
            // Remove old category index entry before overwriting
            if (_categoryIndex.TryGetValue(existing.Category, out var oldList))
                oldList.Remove(code);
        }

        _products[code] = new ProductInfo(category, price);

        if (!_categoryIndex.TryGetValue(category, out var list))
        {
            list = new List<string>();
            _categoryIndex[category] = list;
        }
        list.Add(code);

        _frozen = null; // invalidate frozen snapshot
    }

    /// <summary>
    /// Freezes the catalog into a read-optimized immutable snapshot.
    /// Call after bulk loading is complete to accelerate lookups.
    /// </summary>
    public void Freeze()
        => _frozen = _products.ToFrozenDictionary(_products.Comparer);

    public string? GetCategory(string code)
    {
        var source = _frozen as IReadOnlyDictionary<string, ProductInfo> ?? _products;
        return source.TryGetValue(code, out var info) ? info.Category : null;
    }

    public decimal GetTotalPrice(IEnumerable<string> codes)
    {
        var source = _frozen as IReadOnlyDictionary<string, ProductInfo> ?? _products;
        decimal total = 0m;
        foreach (var code in codes)
        {
            if (source.TryGetValue(code, out var info))
                total += info.Price;
        }
        return total;
    }

    /// <summary>
    /// Returns product codes in the given category.
    /// Uses a reverse index for O(1) lookup instead of scanning all products.
    /// </summary>
    public List<string> GetProductsByCategory(string category)
    {
        if (_categoryIndex.TryGetValue(category, out var list))
            return new List<string>(list);
        return new List<string>();
    }
}

